select message_text from alertlog where message_text like '%ORA-%' and message_text not like '%ORA-12012: error on auto execute of job "SLIU"."MONITOR_DB_SYNC"%' and message_text not like '%ORA-06550: line 4, column 10:%'and message_text not like '%PL/SQL: ORA-01775: looping chain of synonyms%' and message_text not like '%ORA-06550: line 4, column 3:%' and message_text not like '%ORA-1142 signalled during: alter database end backup...%' and message_text not like '%ORA-12012: error on auto execute of job "OPS_USER"."DATAMART_PEAK_DAILY_JOB"%' and message_text not like '%"INTUADMIN"."OFFLOAD_DICT_IN_REDO"%'
/
